#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N, X; scanf("%lld %lld", &N, &X);
        bool ok = false;
        for (long long m = 1; m <= N; ++m) {
            if (X % m) continue;
            long long L = X / m;
            if (L > N) continue;
            if (m + L <= N + 1) { ok = true; break; }
        }
        puts(ok ? "YES" : "NO");
    }
    return 0;
}

