import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        ok = False
        for m in range(1, N+1):
            if X % m:
                continue
            L = X // m
            if L > N:
                continue
            if m + L <= N + 1:
                ok = True
                break
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

